import { useState } from "react";
import { useForm } from "react-hook-form";
import { useDispatch, useSelector } from "react-redux";
import { Link, Navigate } from "react-router-dom";
import { login, register } from "../features/authSlice";

export default function AuthPage({ mode = "login" }) {
  const dispatch = useDispatch();
  const { register: field, handleSubmit, formState: { errors } } = useForm();
  const { user, status, error } = useSelector((state) => state.auth);
  const [serverMessage, setServerMessage] = useState("");
  if (user) return <Navigate to="/" replace />;

  async function onSubmit(values) {
    const action = mode === "register" ? register(values) : login(values);
    const result = await dispatch(action);
    if (result.error) setServerMessage(result.error.message);
  }

  return (
    <main className="auth-shell">
      <form className="card auth-card" onSubmit={handleSubmit(onSubmit)}>
        <p className="eyebrow">Real-time project management</p>
        <h1>{mode === "register" ? "Create account" : "Welcome back"}</h1>
        {mode === "register" && (
          <label>Name<input {...field("name", { required: true, minLength: 2 })} /></label>
        )}
        <label>Email<input type="email" {...field("email", { required: true })} /></label>
        <label>Password<input type="password" {...field("password", { required: true, minLength: 8 })} /></label>
        {(errors.password || error || serverMessage) && <p className="error">Check the form details and try again.</p>}
        <button disabled={status === "loading"}>{status === "loading" ? "Please wait..." : mode === "register" ? "Register" : "Log in"}</button>
        <Link to={mode === "register" ? "/login" : "/register"}>
          {mode === "register" ? "Already have an account?" : "Need an account?"}
        </Link>
      </form>
    </main>
  );
}
