import { createAsyncThunk, createEntityAdapter, createSlice } from "@reduxjs/toolkit";
import { api } from "../services/api";

const adapter = createEntityAdapter({ selectId: (task) => task._id, sortComparer: (a, b) => new Date(b.updatedAt) - new Date(a.updatedAt) });

export const fetchTasks = createAsyncThunk("tasks/fetch", async ({ projectId, params }) => {
  const { data } = await api.get(`/projects/${projectId}/tasks`, { params });
  return data;
});

export const createTask = createAsyncThunk("tasks/create", async ({ projectId, task }) => {
  const tempId = `temp-${Date.now()}`;
  const { data } = await api.post(`/projects/${projectId}/tasks`, task);
  return { data, tempId };
});

export const updateTask = createAsyncThunk("tasks/update", async ({ projectId, taskId, patch }) => {
  const { data } = await api.patch(`/projects/${projectId}/tasks/${taskId}`, patch);
  return data;
});

export const bulkTasks = createAsyncThunk("tasks/bulk", async ({ projectId, payload }) => {
  await api.patch(`/projects/${projectId}/tasks/bulk`, payload);
  return payload;
});

const taskSlice = createSlice({
  name: "tasks",
  initialState: adapter.getInitialState({ presence: [], selectedIds: [], status: "idle" }),
  reducers: {
    taskReceived: adapter.upsertOne,
    taskDeleted: adapter.removeOne,
    bulkApplied(state, action) {
      if (action.payload.operation === "delete") adapter.removeMany(state, action.payload.taskIds);
    },
    presenceUpdated(state, action) {
      state.presence = action.payload;
    },
    toggleSelected(state, action) {
      const id = action.payload;
      state.selectedIds = state.selectedIds.includes(id) ? state.selectedIds.filter((item) => item !== id) : [...state.selectedIds, id];
    },
    clearSelected(state) {
      state.selectedIds = [];
    },
    optimisticTaskUpdate(state, action) {
      adapter.updateOne(state, { id: action.payload._id, changes: action.payload });
    }
  },
  extraReducers: (builder) => {
    builder
      .addCase(fetchTasks.fulfilled, adapter.setAll)
      .addCase(createTask.fulfilled, (state, action) => adapter.upsertOne(state, action.payload.data))
      .addCase(updateTask.fulfilled, adapter.upsertOne)
      .addCase(bulkTasks.fulfilled, (state) => {
        state.selectedIds = [];
      });
  }
});

export const taskSelectors = adapter.getSelectors((state) => state.tasks);
export const { taskReceived, taskDeleted, bulkApplied, presenceUpdated, toggleSelected, clearSelected, optimisticTaskUpdate } = taskSlice.actions;
export default taskSlice.reducer;
