import { useEffect } from "react";
import { useForm } from "react-hook-form";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { createProject, fetchProjects } from "../features/projectSlice";

export default function Dashboard() {
  const dispatch = useDispatch();
  const projects = useSelector((state) => state.projects.items);
  const { register, handleSubmit, reset } = useForm();

  useEffect(() => {
    dispatch(fetchProjects());
  }, [dispatch]);

  async function onSubmit(values) {
    await dispatch(createProject(values));
    reset();
  }

  return (
    <main className="layout">
      <section className="hero">
        <div>
          <p className="eyebrow">Projects</p>
          <h1>Collaborative workspaces</h1>
          <p>Create projects, invite members, and keep task updates synchronized in real time.</p>
        </div>
      </section>
      <section className="grid two">
        <form className="card" onSubmit={handleSubmit(onSubmit)}>
          <h2>Create project</h2>
          <label>Name<input {...register("name", { required: true })} /></label>
          <label>Description<textarea {...register("description")} /></label>
          <button>Create</button>
        </form>
        <div className="stack">
          {projects.length === 0 ? <div className="skeleton">No projects yet</div> : projects.map((project) => (
            <Link className="card project-card" to={`/projects/${project._id}`} key={project._id}>
              <h3>{project.name}</h3>
              <p>{project.description || "No description"}</p>
              <span>{project.status}</span>
            </Link>
          ))}
        </div>
      </section>
    </main>
  );
}
