import { createAsyncThunk, createSlice } from "@reduxjs/toolkit";
import { api } from "../services/api";

export const fetchProjects = createAsyncThunk("projects/fetch", async () => {
  const { data } = await api.get("/projects");
  return data;
});

export const createProject = createAsyncThunk("projects/create", async (payload) => {
  const { data } = await api.post("/projects", payload);
  return data;
});

export const fetchProjectDetails = createAsyncThunk("projects/details", async (projectId) => {
  const { data } = await api.get(`/projects/${projectId}`);
  return data;
});

const projectSlice = createSlice({
  name: "projects",
  initialState: { items: [], current: null, members: [], activity: [], status: "idle" },
  reducers: {},
  extraReducers: (builder) => {
    builder
      .addCase(fetchProjects.fulfilled, (state, action) => {
        state.items = action.payload.map((item) => item.project || item);
      })
      .addCase(createProject.fulfilled, (state, action) => {
        state.items.unshift(action.payload);
      })
      .addCase(fetchProjectDetails.fulfilled, (state, action) => {
        state.current = action.payload.project;
        state.members = action.payload.members;
        state.activity = action.payload.activity;
      });
  }
});

export default projectSlice.reducer;
